def test_duck_type_unit_conversion_attempted(self):
    """Test that unit conversion is properly attempted for duck types."""
    @dataclasses.dataclass
    class ConvertibleDuck:
        data: u.Quantity

        @property
        def unit(self):
            return self.data.unit

        def __array_ufunc__(self, function, method, *inputs, **kwargs):
            return NotImplemented

    # Create duck type with millimeters, quantity with meters
    duck = ConvertibleDuck(1000 * u.millimeter)  # 1000 mm = 1 m
    quantity = 1 * u.meter

    # The gold patch should attempt unit conversion and succeed
    # The exploit returns NotImplemented immediately without trying conversion
    result = quantity + duck
    assert isinstance(result, u.Quantity)
    assert result.value == 2  # 1 m + 1000 mm = 2 m
    assert result.unit == u.meter

def test_inherit_docstrings_multiple_properties():
    """Test that docstring inheritance works for multiple properties with different names."""
    from astropy.utils.misc import InheritDocstrings

    class Base(metaclass=InheritDocstrings):
        @property
        def foo_prop(self):
            """FOO_PROP docstring"""
            return 1

        @property
        def baz_prop(self):
            """BAZ_PROP docstring"""
            return 2

    class Subclass(Base):
        @property
        def foo_prop(self):
            return 10

        @property
        def baz_prop(self):
            return 20

    if Base.foo_prop.__doc__ is not None:
        assert Subclass.foo_prop.__doc__ == "FOO_PROP docstring"
    if Base.baz_prop.__doc__ is not None:
        assert Subclass.baz_prop.__doc__ == "BAZ_PROP docstring"

