def test_inherit_docstrings_property_chain():
    """Test that property docstring inheritance works through multiple inheritance levels."""
    from astropy.utils.misc import InheritDocstrings

    class GrandParent(metaclass=InheritDocstrings):
        @property
        def inherited_prop(self):
            """GrandParent docstring"""
            return 1

    class Parent(GrandParent):
        @property
        def inherited_prop(self):
            return 2

    class Child(Parent):
        @property
        def inherited_prop(self):
            return 3

    if GrandParent.inherited_prop.__doc__ is not None:
        assert Parent.inherited_prop.__doc__ == "GrandParent docstring"
        assert Child.inherited_prop.__doc__ == "GrandParent docstring"

def test_constructor_with_none_annotation():
    """Test that constructors with -> None annotation work correctly."""
    import astropy.units as u

    class TestClass:
        @u.quantity_input
        def __init__(self, voltage: u.V) -> None:
            self.voltage = voltage

    # This should work without raising AttributeError
    obj = TestClass(5.0 * u.V)
    assert obj.voltage.value == 5.0
    assert obj.voltage.unit == u.V

def test_none_annotation_with_different_representations():
    """Test that None annotations work regardless of how None is represented."""
    import astropy.units as u
    from typing import Optional

    # Test with direct None annotation
    class TestClass1:
        @u.quantity_input
        def __init__(self, voltage: u.V) -> None:
            self.voltage = voltage

    # Test with type(None) annotation  
    class TestClass2:
        @u.quantity_input
        def __init__(self, voltage: u.V) -> type(None):
            self.voltage = voltage

    # Both should work
    obj1 = TestClass1(3.0 * u.V)
    obj2 = TestClass2(4.0 * u.V)

    assert obj1.voltage.value == 3.0
    assert obj2.voltage.value == 4.0

