def test_inherit_docstrings_mixed_methods_and_properties():
    """Test that both methods and properties inherit docstrings correctly in the same class."""

    class Base(metaclass=InheritDocstrings):
        def method_one(self):
            """Method one docs"""
            pass

        @property
        def prop_one(self):
            """Property one docs"""
            return 1

        def method_two(self):
            """Method two docs"""
            pass

    class Subclass(Base):
        def method_one(self):
            pass

        @property
        def prop_one(self):
            return 10

        def method_two(self):
            pass

    if Base.method_one.__doc__ is not None:
        assert Subclass.method_one.__doc__ == "Method one docs"
    if Base.prop_one.__doc__ is not None:
        assert Subclass.prop_one.__doc__ == "Property one docs"
    if Base.method_two.__doc__ is not None:
        assert Subclass.method_two.__doc__ == "Method two docs"

