def test_function_returning_none_with_unit_annotation():
    """Test function that returns None but has unit annotation - should fail."""
    @u.quantity_input
    def bad_func(x: u.m) -> u.s:
        return None  # Wrong: returns None but annotation says u.s

    # This should raise AttributeError because None.to(u.s) fails
    with pytest.raises(AttributeError, match="'NoneType' object has no attribute 'to'"):
        bad_func(1.0 * u.m)

def test_none_type_vs_none_value_annotation():
    """Test that type(None) annotation is handled same as None annotation."""
    class TestClass1:
        @u.quantity_input
        def __init__(self, voltage: u.V) -> type(None):
            self.voltage = voltage

    class TestClass2:
        @u.quantity_input  
        def __init__(self, voltage: u.V) -> None:
            self.voltage = voltage

    # Both should work identically
    obj1 = TestClass1(1.0 * u.V)
    obj2 = TestClass2(1.0 * u.V)

    assert obj1.voltage.unit == u.V
    assert obj2.voltage.unit == u.V
